#include <stdint.h>



int main(void)
{

	uint32_t *pClockReg = (uint32_t*)0x40023830;//address of clock control register(AHB1ENR)
	uint32_t *pPortDModeReg = (uint32_t*)0x40020C00;//address of the GPIOD mode register used to control mode
	uint32_t *pPortAModeReg = (uint32_t*)0x40020000;
	uint32_t *pPortOutputReg = (uint32_t*)0x40020C14;//address of the GPIOD output data register used to write
	uint32_t *pPortAInReg = (uint32_t*)0x40020010;

	//enable the clock for GPIOD, GPIOA in the AHB1ENR
	*pClockReg |= (1 << 3);
	*pClockReg |= (1 << 0);
	//configuring PD12 as output
	*pPortDModeReg &= ~(3 << (12 * 2));
	*pPortDModeReg |= (1 <<  (12 * 2));
//	*pPortOutputReg |= 0;
	//configuring PA0 as input mode(GPIOA mode register

	*pPortAModeReg &= ~(3 <<0);
	//read the pin status of the pin PA0(GPIOA input data register)
	while(1){
	uint8_t pinStatus = (uint8_t)(*pPortAInReg & 0x1);
		if(pinStatus){
			//turn on LED
			*pPortOutputReg |= (1 << 12);
		}else{
			//turn off LED
			*pPortOutputReg &= ~(1 << 12);
		}
	}
    /* Loop forever */
	for(;;);
}
